mapper.select:
 
		 
		select 
			db, system, env, dbtype, dbuser, pwd, hostname, port, id_type, id, comments, regdate, upddate, reguserid, upduserid
		from ( 
				select 
					 ROWNUM rn, db, system, env, dbtype, dbuser, pwd, hostname, port, id_type, id, comments, regdate, upddate, reguserid, upduserid
				from (
						select db, system, env, dbtype, dbuser, null as pwd, hostname, port, id_type, id, comments, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piidatabase order by db
					 ) r
				where 
		
	    
		
						
							and db like '%'||#{search1}||'%'
						
						
							and system like '%'||#{search2}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by db
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by db
